import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class SecureServlet extends HttpServlet {

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        String userInput = request.getParameter("input");

        if (userInput != null) {
            // Sanitize and escape user input to prevent XSS
            userInput = sanitizeInput(userInput);

            String output = "<div>" + userInput + "</div>";

            response.getWriter().write(output);
        } else {
            response.getWriter().write("No input provided.");
        }
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization logic here (e.g., using OWASP ESAPI library or HTML escaping functions)
        // For example, you can use Apache Commons Text library for HTML escaping:
        return org.apache.commons.text.StringEscapeUtils.escapeHtml4(input);
    }
}
